export function diceImage(
  sides: number,
  value: number,
  black = false,
): ImageSourcePropType | undefined {
  const dedicated = (black ? DICE_IMAGES_BLACK : DICE_IMAGES)[sides];
  if (dedicated && dedicated[value]) return dedicated[value];
  // Fall back to the circle placeholder for arbitrary die types (e.g. d7).
  return (black ? CIRCLE_IMAGES_BLACK : CIRCLE_IMAGES)[value];
}
